const fs = require('fs');
const path = require('path');
const vaultPath = 'C:/Users/manaz/Desktop/JobFilter/JobFilterV1/Obsidian_Memory/Obsidian_Vault';
const res = $input.first().json || {};
const score = Number(res.score ?? res.intakeScore ?? 0);
const tier = score >= 80 ? 'gold' : score >= 55 ? 'silver' : 'bronze';
const now = new Date();
const id = res.id || ('intake-' + now.getTime());
const slug = String(id).toLowerCase().replace(/[^a-z0-9]+/g, '-');
const dir = path.join(vaultPath, 'JobFilter', 'Outcomes', tier);
fs.mkdirSync(dir, { recursive: true });
const file = path.join(dir, slug + '.md');
const md = `---
type: intake
intake_id: ${id}
score: ${score}
tier: ${tier}
logged_at: ${now.toISOString()}
tags: [jobfilter, intake, ${tier}]
---

# Intake — ${id} (${tier.toUpperCase()})

**Score:** ${score}
**Tier:** ${tier}
**Logged:** ${now.toISOString()}

## Raw payload

\`\`\`json
${JSON.stringify(res, null, 2)}
\`\`\`
`;
fs.writeFileSync(file, md);
return [{ json: { id, score, tier, file, scoreResponse: res } }];
